<?php
namespace App\Models;
class InformeModel extends BaseCatalog { public array $fallasChaquetas=['Corto Circuito','Tracción','Aplastamiento','Corte en Chaqueta']; public array $fallasEnchufe=['Sin Enchufe Macho','Cabezal Quebrado','Cuerpo enchufe Quebrado','Loza Quebrada','Sin Pines','Sin Piloto','Collerín Quebrado','Falta de pernos','Pines sulfatados','Corto Circuito']; public array $lugares=['Mufas termocontraibles','Cable piloto','Enchufes','Chaquetas','Aislación Exterior']; public array $causas=['Tracción','Sobrecorriente','Aplastamiento','Cortocircuito','Pines sueltos','Impacto','Enrolla cable','Roca tronadura','Fatiga de material','Agua / Humedad','Manilla enrollada']; public function list():array{return $this->fetchAll('SELECT i.*, c.numero_cable, CONCAT(u.nombre," ",u.apellido) supervisor FROM informes_cable i JOIN cables c ON c.id=i.cable_id LEFT JOIN usuarios u ON u.id=i.supervisor_id WHERE i.deleted_at IS NULL ORDER BY i.id DESC');} }
